/*
 * Parse Telegram Command
 * ======================
 * Purpose: Extracts the command and parameters from the Telegram message.
 *          Supports: /add, /list, /get, /update, /delete, /search, /help
 * 
 * Input: Telegram message text
 * Output: Parsed command object with command name and parameters
 */

const text = $input.first().json.text || '';
const chatId = $input.first().json.chatId;

const commandMatch = text.match(/^\/([a-z]+)/i);
const command = commandMatch ? commandMatch[1].toLowerCase() : 'unknown';
const paramsText = text.replace(/^\/[a-z]+\s*/i, '').trim();

let parsed = {
  command: command,
  chatId: chatId,
  rawParams: paramsText,
  params: {}
};

switch (command) {
  case 'add':
    const addParts = paramsText.split(',').map(p => p.trim());
    if (addParts.length >= 4) {
      parsed.params = {
        name: addParts[0],
        price: parseFloat(addParts[1]) || 0,
        quantity: parseInt(addParts[2]) || 0,
        category: addParts[3]
      };
    } else {
      parsed.params.error = 'Invalid format. Use: /add name, price, quantity, category';
    }
    break;
  case 'list':
    parsed.params.category = paramsText || null;
    break;
  case 'get':
    parsed.params.id = parseInt(paramsText) || null;
    if (!parsed.params.id) parsed.params.error = 'Invalid format. Use: /get id';
    break;
  case 'update':
    const updateParts = paramsText.split(' ');
    parsed.params.id = parseInt(updateParts[0]) || null;
    parsed.params.updates = {};
    if (parsed.params.id) {
      for (let i = 1; i < updateParts.length; i++) {
        const [field, value] = updateParts[i].split('=');
        if (field && value !== undefined) {
          if (field === 'price') parsed.params.updates[field] = parseFloat(value);
          else if (field === 'quantity') parsed.params.updates[field] = parseInt(value);
          else parsed.params.updates[field] = value;
        }
      }
      if (Object.keys(parsed.params.updates).length === 0) {
        parsed.params.error = 'No valid updates. Use: /update id field=value';
      }
    } else {
      parsed.params.error = 'Invalid format. Use: /update id field=value';
    }
    break;
  case 'delete':
    parsed.params.id = parseInt(paramsText) || null;
    if (!parsed.params.id) parsed.params.error = 'Invalid format. Use: /delete id';
    break;
  case 'search':
    parsed.params.searchText = paramsText;
    if (!paramsText) parsed.params.error = 'Invalid format. Use: /search text';
    break;
  case 'help':
    break;
  default:
    parsed.params.error = 'Unknown command. Use /help to see available commands.';
}

return [{ json: parsed }];

