const items = $input.all();
const chatId = $('Parse Command and Parameters').first().json.chatId;
const category = $('Parse Command and Parameters').first().json.params.category;

if (items.length === 0) {
  return [{
    json: {
      chatId: chatId,
      message: category 
        ? `📭 No products found in category "${category}"`
        : '📭 No products in database'
    }
  }];
}

let message = category 
  ? `📦 Products in "${category}" (${items.length}):\n\n`
  : `📦 All Products (${items.length}):\n\n`;

items.forEach((item, index) => {
  const p = item.json;
  message += `${index + 1}. [ID: ${p.id}] ${p.name}\n`;
  message += `   💰 $${p.price} | 📊 Qty: ${p.quantity} | 🏷️ ${p.category}\n\n`;
});

return [{ json: { chatId, message } }];

